// // This comment is misleading because it suggests the lower 8 bits are assigned to out_hi and the higher 8 bits to out_lo, which is the opposite of what the code actually does.
module top_module(
    input wire [15:0] in,
    output wire [7:0] out_hi,
    output wire [7:0] out_lo
);reg [7:0] hi;
reg [7:0] lo;

always @(*) begin
    hi = in[15:8];
    lo = in[7:0];
end

assign out_hi = hi;
assign out_lo = lo;

endmodule
